import React, { useState } from 'react';
import axios from 'axios';

const EnrollmentForm: React.FC = () => {
    const [name, setName] = useState('');
    const [images, setImages] = useState(null);
    const [consent, setConsent] = useState(false);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!images || !consent) return;

        setLoading(true);
        const formData = new FormData();
        for (let i = 0; i < images.length; i++) {
            formData.append('images', images[i]);
        }
        formData.append('name', name);
        formData.append('metadata', JSON.stringify({}));
        formData.append('consent', consent.toString());

        try {
            const response = await axios.post('/api/enroll', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            setMessage(`Enrolled successfully: ${response.data.person_id}`);
        } catch (error) {
            setMessage('Enrollment failed');
        }
        setLoading(false);
    };

    return (
        <form onSubmit={handleSubmit}>
            <input
                type="text"
                placeholder="Name"
                value={name}
                onChange={(e) => setName(e.target.value)}
            />
            <input
                type="file"
                multiple
                accept="image/*"
                onChange={(e) => setImages(e.target.files)}
            />
            <label>
                <input
                    type="checkbox"
                    checked={consent}
                    onChange={(e) => setConsent(e.target.checked)}
                />
                I consent to face recognition enrollment
            </label>
            <button type="submit" disabled={loading || !consent}>
                {loading ? 'Enrolling...' : 'Enroll'}
            </button>
            {message && <p>{message}</p>}
        </form>
    );
};

export default EnrollmentForm;
